import {{ Injectable }} from '@nestjs/common';
import {{ BlogService }} from './models/blog.model';
import {{ BlogServiceRepository }} from './repositories/blog.repository';

@Injectable()
export class BlogServiceService {{
  constructor(
    private readonly repository: BlogServiceRepository,
  ) {{}}

  async findAll(): Promise<BlogService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<BlogService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<BlogService>): Promise<BlogService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<BlogService>): Promise<BlogService> {{
    return this.repository.update(id, data);
  }}
}}
